mapper.select:
select

from product_review_request r

where r.del_flag = '0'

    and (
        r.review_no like concat('%', #{keyword}, '%')
        or r.system_spu_code like concat('%', #{keyword}, '%')
        or r.product_name_after like concat('%', #{keyword}, '%')
        or r.seller_name like concat('%', #{keyword}, '%')
    )


    and r.review_type = #{reviewType}


    and find_in_set(r.review_type, #{reviewTypes})


    and r.review_status = #{reviewStatus}


    and r.seller_id = #{sellerId}


    and r.category_id = #{categoryId}


    and r.submit_terminal = #{submitTerminal}


    and r.submit_time >= #{params.beginTime}


    and r.submit_time <= #{params.endTime}

order by
    case when r.review_status = 'PENDING' then 0 else 1 end,
    r.submit_time asc,
    r.review_id desc

select r.* from product_review_request r inner join ( select spu_id, max(review_id) as review_id from product_review_request where del_flag = '0' and spu_id in
#{spuId}
group by spu_id ) latest on latest.review_id = r.review_id where r.del_flag = '0'

mapper.update:
update product_review_item
set item_status = #{itemStatus}
where review_id = #{reviewId}

mapper.insert:
insert into product_review_snapshot(
    review_id, item_id, snapshot_role, payload_type, payload_json, payload_hash, create_time
) values (
    #{reviewId}, #{itemId}, #{snapshotRole}, #{payloadType}, #{payloadJson}, #{payloadHash}, sysdate()
)

insert into product_review_operation_log(
    review_id, spu_id, operation_type, before_status, after_status,
    operator_terminal, operator_id, operator_name, operation_time, reason, remark
) values (
    #{reviewId}, #{spuId}, #{operationType}, #{beforeStatus}, #{afterStatus},
    #{operatorTerminal}, #{operatorId}, #{operatorName}, sysdate(), #{reason}, #{remark}
)
